16	impl ProviderClient {
17	    pub fn from_model(model: &str) -> Result<Self, ApiError> {
18	        Self::from_model_with_anthropic_auth(model, None)
19	    }
20	
21	    pub fn from_model_with_anthropic_auth(
22	        model: &str,
23	        anthropic_auth: Option<AuthSource>,
24	    ) -> Result<Self, ApiError> {
25	        let resolved_model = providers::resolve_model_alias(model);
26	        match providers::detect_provider_kind(&resolved_model) {
27	            ProviderKind::Anthropic => Ok(Self::Anthropic(match anthropic_auth {
28	                Some(auth) => AnthropicClient::from_auth(auth),
29	                None => AnthropicClient::from_env()?,
30	            })),
31	            ProviderKind::Xai => Ok(Self::Xai(OpenAiCompatClient::from_env(
32	                OpenAiCompatConfig::xai(),
33	            )?)),
34	            ProviderKind::OpenAi => Ok(Self::OpenAi(OpenAiCompatClient::from_env(
35	                OpenAiCompatConfig::openai(),
36	            )?)),
37	        }
38	    }
39	
40	    #[must_use]
41	    pub const fn provider_kind(&self) -> ProviderKind {
42	        match self {
43	            Self::Anthropic(_) => ProviderKind::Anthropic,
44	            Self::Xai(_) => ProviderKind::Xai,
45	            Self::OpenAi(_) => ProviderKind::OpenAi,
46	        }
47	    }
48	
49	    #[must_use]
50	    pub fn with_prompt_cache(self, prompt_cache: PromptCache) -> Self {
51	        match self {
52	            Self::Anthropic(client) => Self::Anthropic(client.with_prompt_cache(prompt_cache)),
53	            other => other,
54	        }
55	    }
56	
57	    #[must_use]
58	    pub fn prompt_cache_stats(&self) -> Option<PromptCacheStats> {
59	        match self {
60	            Self::Anthropic(client) => client.prompt_cache_stats(),
61	            Self::Xai(_) | Self::OpenAi(_) => None,
62	        }
63	    }
64	
65	    #[must_use]
66	    pub fn take_last_prompt_cache_record(&self) -> Option<PromptCacheRecord> {
67	        match self {
68	            Self::Anthropic(client) => client.take_last_prompt_cache_record(),
69	            Self::Xai(_) | Self::OpenAi(_) => None,
70	        }
71	    }
72	
73	    pub async fn send_message(
74	        &self,
75	        request: &MessageRequest,
76	    ) -> Result<MessageResponse, ApiError> {
77	        match self {
78	            Self::Anthropic(client) => client.send_message(request).await,
79	            Self::Xai(client) | Self::OpenAi(client) => client.send_message(request).await,
80	        }
81	    }
82	
83	    pub async fn stream_message(
84	        &self,
85	        request: &MessageRequest,
86	    ) -> Result<MessageStream, ApiError> {
87	        match self {
88	            Self::Anthropic(client) => client
89	                .stream_message(request)
